ALTER TABLE public.recurring_demands DROP CONSTRAINT IF EXISTS recurring_demands_frequency_check;
ALTER TABLE public.recurring_demands ADD CONSTRAINT recurring_demands_frequency_check CHECK (frequency = ANY (ARRAY['daily'::text, 'weekly'::text, 'biweekly'::text, 'monthly'::text, 'yearly'::text, 'test_1min'::text, 'test_5min'::text]));